import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonIOException;
import com.google.gson.JsonNull;
import com.google.gson.JsonParseException;
import com.google.gson.JsonSyntaxException;
import com.google.gson.internal.Streams;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.io.EOFException;
import java.io.IOException;
import java.lang.reflect.Method;

public class StreamsTest {

    JsonReader mockReader;

    @BeforeEach
    public void setUp() {
        mockReader = mock(JsonReader.class);
    }

    @Test
    public void testParse_ReturnsJsonElement_WhenReaderNotEmpty() throws Exception {
        // Arrange
        doNothing().when(mockReader).peek();
        JsonElement expectedElement = mock(JsonElement.class);

        try (MockedStatic<TypeAdapters> typeAdaptersStatic = Mockito.mockStatic(TypeAdapters.class)) {
            // Mock static field TypeAdapters.JSON_ELEMENT.read(reader)
            // Since JSON_ELEMENT is a static final field, we need to mock the read method on it.
            // We'll mock TypeAdapters.JSON_ELEMENT as a JsonAdapter with a read method.
            var jsonElementAdapter = mock(TypeAdapters.JSON_ELEMENT.getClass());
            // We cannot mock the field directly, so we mock the static method read to delegate to our mock.
            // But since JSON_ELEMENT is a field, we have to mock TypeAdapters.JSON_ELEMENT.read(reader) by mocking TypeAdapters.JSON_ELEMENT

            // Use reflection to get JSON_ELEMENT field and mock its read method
            var jsonElementField = TypeAdapters.class.getDeclaredField("JSON_ELEMENT");
            jsonElementField.setAccessible(true);
            Object jsonElementAdapterInstance = jsonElementField.get(null);
            var adapterMock = Mockito.mock(jsonElementAdapterInstance.getClass());
            // Replace the JSON_ELEMENT field with our mock temporarily
            jsonElementField.set(null, adapterMock);

            when(adapterMock.read(mockReader)).thenReturn(expectedElement);

            // Act
            JsonElement result = Streams.parse(mockReader);

            // Assert
            assertSame(expectedElement, result);

            // Restore original JSON_ELEMENT field
            jsonElementField.set(null, jsonElementAdapterInstance);
        }
    }

    @Test
    public void testParse_ReturnsJsonNull_WhenEmptyDocument() throws Exception {
        // Arrange
        doThrow(new EOFException()).when(mockReader).peek();

        // Act
        JsonElement result = Streams.parse(mockReader);

        // Assert
        assertSame(JsonNull.INSTANCE, result);
    }

    @Test
    public void testParse_ThrowsJsonSyntaxException_OnPrematureEOF() throws Exception {
        // Arrange
        doThrow(new EOFException()).when(mockReader).peek();

        // Simulate isEmpty = false by making peek() succeed once then throw EOFException on next call
        JsonReader spyReader = spy(mockReader);
        doNothing().doThrow(new EOFException()).when(spyReader).peek();

        try (MockedStatic<TypeAdapters> typeAdaptersStatic = Mockito.mockStatic(TypeAdapters.class)) {
            var jsonElementField = TypeAdapters.class.getDeclaredField("JSON_ELEMENT");
            jsonElementField.setAccessible(true);
            Object jsonElementAdapterInstance = jsonElementField.get(null);
            var adapterMock = Mockito.mock(jsonElementAdapterInstance.getClass());
            jsonElementField.set(null, adapterMock);

            // Make adapter.read throw EOFException to simulate premature EOF after peek
            when(adapterMock.read(spyReader)).thenThrow(new EOFException());

            // Act & Assert
            assertThrows(JsonSyntaxException.class, () -> Streams.parse(spyReader));

            jsonElementField.set(null, jsonElementAdapterInstance);
        }
    }

    @Test
    public void testParse_ThrowsJsonSyntaxException_OnMalformedJsonException() throws Exception {
        // Arrange
        doNothing().when(mockReader).peek();

        try (MockedStatic<TypeAdapters> typeAdaptersStatic = Mockito.mockStatic(TypeAdapters.class)) {
            var jsonElementField = TypeAdapters.class.getDeclaredField("JSON_ELEMENT");
            jsonElementField.setAccessible(true);
            Object jsonElementAdapterInstance = jsonElementField.get(null);
            var adapterMock = Mockito.mock(jsonElementAdapterInstance.getClass());
            jsonElementField.set(null, adapterMock);

            when(adapterMock.read(mockReader)).thenThrow(new MalformedJsonException("malformed"));

            // Act & Assert
            assertThrows(JsonSyntaxException.class, () -> Streams.parse(mockReader));

            jsonElementField.set(null, jsonElementAdapterInstance);
        }
    }

    @Test
    public void testParse_ThrowsJsonIOException_OnIOException() throws Exception {
        // Arrange
        doNothing().when(mockReader).peek();

        try (MockedStatic<TypeAdapters> typeAdaptersStatic = Mockito.mockStatic(TypeAdapters.class)) {
            var jsonElementField = TypeAdapters.class.getDeclaredField("JSON_ELEMENT");
            jsonElementField.setAccessible(true);
            Object jsonElementAdapterInstance = jsonElementField.get(null);
            var adapterMock = Mockito.mock(jsonElementAdapterInstance.getClass());
            jsonElementField.set(null, adapterMock);

            when(adapterMock.read(mockReader)).thenThrow(new IOException("io"));

            // Act & Assert
            assertThrows(JsonIOException.class, () -> Streams.parse(mockReader));

            jsonElementField.set(null, jsonElementAdapterInstance);
        }
    }

    @Test
    public void testParse_ThrowsJsonSyntaxException_OnNumberFormatException() throws Exception {
        // Arrange
        doNothing().when(mockReader).peek();

        try (MockedStatic<TypeAdapters> typeAdaptersStatic = Mockito.mockStatic(TypeAdapters.class)) {
            var jsonElementField = TypeAdapters.class.getDeclaredField("JSON_ELEMENT");
            jsonElementField.setAccessible(true);
            Object jsonElementAdapterInstance = jsonElementField.get(null);
            var adapterMock = Mockito.mock(jsonElementAdapterInstance.getClass());
            jsonElementField.set(null, adapterMock);

            when(adapterMock.read(mockReader)).thenThrow(new NumberFormatException("number format"));

            // Act & Assert
            assertThrows(JsonSyntaxException.class, () -> Streams.parse(mockReader));

            jsonElementField.set(null, jsonElementAdapterInstance);
        }
    }
